def reduce_todos(state, action):
    action_type = action.get("type")
    if action_type == "clear":
        return {"items": []}, None
    return state, {"type": "unknown_action"}


def build_report(state):
    items = state.get("items", [])
    return {"total": len(items), "visible_ids": [item.get("id") for item in items]}

def test_unknown_action_returns_error():
    state = {"items": [{"id": "a"}]}
    next_state, error = reduce_todos(state, {"type": "missing"})
    assert next_state == state
    assert error["type"] == "unknown_action"
